   271	func TestDeque_ConcurrentPushPopStealNoLostOrDuplicateItems(t *testing.T) {
   272		const itemCount = 1000
   273	
   274		d := NewDeque()
   275		var pushesDone atomic.Bool
   276		var wg sync.WaitGroup
   277		consumed := make(chan int, itemCount*2)
   278	
   279		for i := 0; i < 8; i++ {
   280			wg.Add(1)
   281			go func() {
   282				defer wg.Done()
   283				for {
   284					item, ok := d.StealTop()
   285					if ok {
   286						consumed <- item.(int)
   287						continue
   288					}
   289					if pushesDone.Load() && d.IsEmpty() {
   290						return
   291					}
   292					runtime.Gosched()
   293				}
   294			}()
   295		}
   296	
   297		wg.Add(1)
   298		go func() {
   299			defer wg.Done()
   300			for i := 0; i < itemCount; i++ {
   301				d.PushBottom(i)
   302				if i%4 == 0 {
   303					item, ok := d.PopBottom()
   304					if ok {
   305						consumed <- item.(int)
   306					}
   307				}
   308				if i%17 == 0 {
   309					runtime.Gosched()
   310				}
   311			}
   312			pushesDone.Store(true)
   313	
   314			for {
   315				item, ok := d.PopBottom()
   316				if ok {
   317					consumed <- item.(int)
   318					continue
   319				}
   320				if d.IsEmpty() {
   321					return
   322				}
   323				runtime.Gosched()
   324			}
   325		}()
   326	
   327		wg.Wait()
   328		close(consumed)
   329	
   330		seen := make(map[int]bool, itemCount)
   331		for item := range consumed {
   332			if item < 0 || item >= itemCount {
   333				t.Fatalf("unexpected item %d", item)
   334			}
   335			if seen[item] {
   336				t.Fatalf("duplicate item %d", item)
   337			}
   338			seen[item] = true
   339		}
   340		if len(seen) != itemCount {
   341			t.Fatalf("expected %d consumed items, got %d", itemCount, len(seen))
   342		}
   343	}
